[DataContract]
public final class SalesPackingSlipBusinessEventContract extends BusinessEventsContract
{
    private SalesId             salesId;
    private PackingSlipId       packingSlipId;
    private Qty                 totalQuantity;
    private AmountCur           totalAmount;
    private str                 transactionType;
    private str                 source;
    private CurrencyCode        currencyCode;
    private TransDate           transactionDate;
    private SalesAgreementId    salesAgreementNumber;
    private CustAccount         customerAccount;
    private RefRecId            recordId;
    private str                 bolNo;
    private TransDate           bolDate;
    private str                 portOfLoading;
    private str                 portOfDischarge;
    private str                 shipmentFrom;
    private str                 shipmentTo;

    // ---> NEW VARIABLE ADDED <---
    private str                 etgDealNumber;

    private List                lines;

}

Method.Source:
protected void initialize(CustPackingSlipJour _journal)
{
    SalesTable                salesTable;
    ETG_SalesTableTrade       etgSalesTableTrade;
    SalesAgreementHeader      salesAgreementHeader;
    ETG_BILLOFLADING          eTG_BILLOFLADING;
    ETG_SalesAgreementHeader  eTG_SalesAgreementHeader;
    AgreementHeaderDefault    agreementHeaderDefault; // ---> NEW TABLE DECLARATION <---

    salesId         = _journal.SalesId;
    packingSlipId   = _journal.PackingSlipId;
    transactionType = 'SalesPackingSlip';
    source          = 'D365';

    transactionDate = _journal.DeliveryDate;
    customerAccount = _journal.OrderAccount;
    recordId        = _journal.RecId;

    salesTable = SalesTable::find(_journal.SalesId);
    currencyCode = salesTable.CurrencyCode;

    select firstonly salesAgreementHeader
        where salesAgreementHeader.RecId == salesTable.MatchingAgreement;

    if (salesAgreementHeader.RecId)
    {
        salesAgreementNumber = salesAgreementHeader.SalesNumberSequence;


        select firstonly agreementHeaderDefault
            where agreementHeaderDefault.AgreementHeader == salesAgreementHeader.RecId;

        if (agreementHeaderDefault.RecId)
        {
            etgDealNumber = agreementHeaderDefault.ETGDealNumber;
        }
    }

    select firstonly eTG_BILLOFLADING
        where eTG_BILLOFLADING.SalesId == _journal.SalesId;

    bolNo           = eTG_BILLOFLADING.BOLNo;
    bolDate         = eTG_BILLOFLADING.BOLDate;

    select firstonly etgSalesTableTrade
        where etgSalesTableTrade.SalesId == _journal.SalesId;

    portOfLoading   = etgSalesTableTrade.PortOfLoading;
    portOfDischarge = etgSalesTableTrade.PortOfDischarge;

    shipmentFrom    = etgSalesTableTrade.CountryOfOriginOfGoods;
    shipmentTo      = etgSalesTableTrade.CountryOfFinalDestination;

    // Initialize the lines list
    lines = new List(Types::Class);

    this.populateLines(_journal);
}

private void populateLines(CustPackingSlipJour _journal)
{
    CustPackingSlipTrans packingSlipTrans;

    totalQuantity = 0;
    totalAmount = 0;

    // Loop through lines for this packing slip
    while select packingSlipTrans
        where packingSlipTrans.SalesId == _journal.SalesId
           && packingSlipTrans.PackingSlipId == _journal.PackingSlipId
           && packingSlipTrans.DeliveryDate == _journal.DeliveryDate
    {
        totalQuantity += packingSlipTrans.Qty;
        totalAmount   += packingSlipTrans.ValueMST;

        // Instantiate the line contract and add it to our List Array
        SalesPackingSlipLineBusinessEventContract lineContract = SalesPackingSlipLineBusinessEventContract::construct(
            packingSlipTrans.ItemId,
            packingSlipTrans.Qty,
            packingSlipTrans.ValueMST,
            currencyCode);

        lines.addEnd(lineContract);
    }
}

public static SalesPackingSlipBusinessEventContract newFromCustPackingSlipJour(CustPackingSlipJour _journal)
{
    var contract = new SalesPackingSlipBusinessEventContract();
    contract.initialize(_journal);
    return contract;
}

// --- The DataCollectionAttribute explicitly tells D365 to serialize this as a JSON array ---
[DataMember('Lines'),
 DataCollectionAttribute(Types::Class, classStr(SalesPackingSlipLineBusinessEventContract)),
 BusinessEventsDataMember('Packing Slip Lines')]
public List parmLines(List _lines = lines)
{
    lines = _lines;
    return lines;
}

